const errorData = $input.all();
const err = errorData[0]?.json || {};

// Error Trigger provides: execution.id, workflow.id, workflow.name, error.message
const execution = err.execution || {};
const workflow = err.workflow || {};
const error = err.error || {};

return [{
  json: {
    workflow_name: workflow.name || 'unknown',
    workflow_id: workflow.id || null,
    execution_id: execution.id || null,
    status: 'error',
    message: `Workflow failed: ${workflow.name || 'unknown'}`,
    error_message: error.message || JSON.stringify(error).slice(0, 500),
    client_id: null,
    items_processed: null
  }
}];

// Called by other workflows via Execute Workflow node
// Expected input: workflow_name, status, message, client_id, items_processed
const data = $input.all();
const input = data[0]?.json || {};

return [{
  json: {
    workflow_name: input.workflow_name || 'unknown',
    workflow_id: input.workflow_id || null,
    execution_id: input.execution_id || null,
    status: input.status || 'success',
    message: input.message || `${input.workflow_name || 'Workflow'} completed successfully`,
    client_id: input.client_id || null,
    items_processed: input.items_processed || null,
    error_message: null
  }
}];
